\section{Proof}\label{sec:omitted_proof}
\subsection{Proof of Theorem~\ref{thm:mmd_bound}}
\begin{thm1}
 Assume the value function $R(s,a)$ is $c$-Lipschitz w.r.t the input action $a$. Define the implicit policy that performs \Cref{eq_svgd} for $L$ steps with $N$ particles as $\pi_{N}^{L}$. We have
 \begin{equation*}
 \mathrm{MMD}^2(\mu, \pi_{N}^{L}) = \mathrm{MMD}^2(\pi_{N}^{0}, \pi_{N}^{L}) \leq \frac{2\epsilon L}{\sigma\sqrt{e}}\left(\frac{c}{\alpha} + \frac{1}{\sigma\sqrt{e}}\right).
 \end{equation*}
\end{thm1}
\begin{proof}
 When $R(s,a)$ is $c$-Lipschitz, we know that $\|\nabla_{a_j} R(s,a_j)\|_\infty \leq c$. Additionally, we have another key observation that the kernel $k$ also has Lipschitz property. Formally,
 \begin{align*}
 k(x+\delta,y) - k(x,y) = \exp(-\|x-y\|^2/2\sigma^2) - \exp(-\|x + \delta - y\|^2/2\sigma^2) \leq \frac{\|\delta\|_\infty}{\sigma\sqrt{e}}.
 \end{align*}
 In other words, the kernel $k$ is $\frac{1}{\sigma\sqrt{e}}$-Lipschitz. Combining these two properties, we have
 \begin{align*}
 \|h(s,x)\|_\infty &= \|\mathbb{E}_{a_j \sim \mu_0} \left[ k(a_j, x) \nabla_{a_j} R(s, a_j) / \alpha + \nabla_{a_j} k(a_j, x) \right]\|_\infty 
 &\leq \sup_{a_j} k(a_j,x) \cdot \frac{c}{\alpha} + \sup_{a_j} \|\nabla_{a_j} k(a_j, x)\|_\infty 
 &\leq \frac{c}{\alpha} + \frac{1}{\sigma\sqrt{e}}.
 \end{align*}
 The square of MMD distance is calculated as follows:
 \begin{align*}
 \text{MMD}^2(\pi_N^L,\pi_N^0) = \mathbb{E}_{x,y \sim \pi_N^0} k(x,y) + \mathbb{E}_{x,y \sim \pi_N^L} k(x,y) - 2\mathbb{E}_{x \sim \pi_N^0, y \sim \pi_N^L} k(x,y).
 \end{align*}
 Define $K:=\frac{1}{\sigma\sqrt{e}}$ and $H:=\frac{c}{\alpha} + \frac{1}{\sigma\sqrt{e}}$. Let us consider the condition of a single pair of particles $x, y$ after one iteration. We have
 \begin{align*}
 &\quad k(x, y) + k(x+\epsilon h(x), y+\epsilon h(y)) - k(x+\epsilon h(x), y) - k(x, y+\epsilon h(y)) 
 &\leq |k(x, y) - k(x+\epsilon h(x), y)| + |k(x+\epsilon h(x), y+\epsilon h(y)) - k(x, y+\epsilon h(y))| 
 &\leq 2\epsilon KH.
 \end{align*}
 Denote $x^{(k)}$ as the particle $x$ after the $k$-th iteration, we have
 \begin{align*}
 \text{MMD}^2(\pi_N^L,\pi_N^0) &= \mathbb{E}_{x,y \sim \pi_N^0} k(x,y) + \mathbb{E}_{x,y \sim \pi_N^L} k(x,y) - 2\mathbb{E}_{x \sim \pi_N^0, y \sim \pi_N^L} k(x,y) 
 &= \frac{1}{n^2} \sum_{x,y} \left[k(x^{(0)},y^{(0)}) + k(x^{(L)},y^{(L)}) - k(x^{(L)},y^{(0)}) - k(x^{(0)},y^{(L)})\right] 
 &\leq 2\epsilon KHL.
 \end{align*}
\end{proof}
\subsection{Proof of Theorem~\ref{thm:support_shift}}
\begin{thm2}
Define the $\epsilon$-support of a distribution $P$ as $\mathrm{supp}_\epsilon(P) := \{x:p(x) \geq \epsilon\}$. We have
\begin{equation*}
 \mathrm{supp}_\epsilon(\pi_{N}^{L}(\cdot|s)) \not\subseteq \mathrm{supp}_\epsilon(\mu(\cdot|s)).
\end{equation*}
\end{thm2}
The proof can be divided into two settings, where the policy distribution is discrete and continuous. We first present the simple proof for the discrete setting.
\begin{proof}
 Denote the support of the behavioral policy as $\text{supp}(\pi_N^0)=\{a_1,...,a_N\}$. If the support of the learned policy from one-step SVGD $\text{supp}(\pi_N^1)$ is a subset of $\text{supp}(\pi_N^0)$, then we know that $a_1$ is updated to $a_i \in \text{supp}(\pi_N^0)$. This indicates that
 \[
 a_i = a_1 + \epsilon h(a_1) = a_1 + \epsilon \mathbb{E}_{a_j \sim \pi_N^0} \left[ k(a_j, a_1) \nabla_{a_j} R(s, a_j) / \alpha + \nabla_{a_j} k(a_j, a_1) \right].
 \]
 Note that a little disturbance in any of the dimensions of $\nabla_{a_j} R(s, a_j)$ will make the equation invalid when the other derivatives of $R$ are fixed. Therefore, the equation is almost surely invalid.
\end{proof}
As for the continuous setting, we typically assume that the policies before and after an SVGD update both follow Gaussian distributions, which is a widely used assumption. Formally, we assume that $\pi_N^0 \sim \mathcal{N}(\mu_1,\sigma_1^2), \pi_N^1 \sim \mathcal{N}(\mu_2, \sigma^2_2)$.
\begin{proof}
 We consider the gradient of an arbitrary particle $a$ sampled from $\pi_N^0$. We know that 
 \[
 h(a) = \mathbb{E}_{a_j \sim \pi_N^0} \left[ k(a_j, a) \nabla_{a_j} R(s, a_j) / \alpha + \nabla_{a_j} k(a_j, a) \right].
 \]
 Let us investigate the first term. We also know that
 \begin{align*}
 \nabla_{a_j} R(s, a_j) &= \nabla_{a_j} \log \pi_N^1(a_j|s) 
 &= \nabla_{a_j} \log \left[\frac{1}{\sqrt{2\pi}\sigma_2} \exp(-\frac{(a_j-\mu_2)^2}{2\sigma^2_2})\right] 
 &= \frac{-\frac{1}{\sqrt{2\pi}\sigma_2} \exp(-\frac{(a_j-\mu_2)^2}{2\sigma^2_2}) \frac{a_j-\mu_2}{\sigma^2_2}}{\frac{1}{\sqrt{2\pi}\sigma_2} \exp(-\frac{(a_j-\mu_2)^2}{2\sigma^2_2})} 
 &= \frac{\mu_2-a_j}{\sigma^2_2}.
 \end{align*}
 Then, we calculate the second term:
 \begin{align*}
 \nabla_{a_j} k(a_j, a) &= k(a_j, a) \frac{a_j-a}{\sigma^2_1}.
 \end{align*}
 Combining both terms, we have
 \begin{align*}
 h(a) &= \mathbb{E}_{a_j \sim \pi_N^0} \left[k(a_j, a)(\frac{\mu_2-a_j}{\alpha \sigma^2_2} + \frac{a_j-a}{\sigma^2_1})\right] 
 &= \mathbb{E}_{a_j \sim \pi_N^0} \left[k(a_j, a)\frac{\mu_1-a_j}{\alpha \sigma^2_2}\right] + \mathbb{E}_{a_j \sim \pi_N^0} \left[k(a_j, a)(\frac{\mu_2-\mu_1}{\alpha \sigma^2_2} + \frac{a_j-a}{\sigma^2_1})\right] 
 &= \mathbb{E}_{a_j \sim \pi_N^0} \left[k(a_j, a)(\frac{\mu_2-\mu_1}{\alpha \sigma^2_2} + \frac{a_j-a}{\sigma^2_1})\right].
 \end{align*}
 The last equation above is because of the symmetry of Gaussian distributions. We now focus on the first dimension of particles. Without loss of generality, we assume that $\mu_{1,1} \leq \mu_{2,1}$. From the $\epsilon$-support of $\pi_N^0$, which is a closed region, we choose $a$ with the smallest value in the first dimension, i.e., $(a-x)_1 \leq 0$ for any $x \in \text{supp}(\pi_N^0)$. This indicates that the first dimension of $h(a)$ is strictly greater than zero, which means that the updated particle of $a$ is out of the $\epsilon$-support of $\pi_N^0$.
\end{proof}
\section{Experimental Details}
\label{sec_exp_details}
\subsection{Offline RL Evaluation Details}
\noindent \textbf{Environments, tasks, and datasets.}  \
In the offline setting, VGF is evaluated on different kinds of datasets from various environments.
For MuJoCo environments, we have the following datasets.
\begin{itemize}[leftmargin=1.5em, labelsep=0.5em]
\item \texttt{halfcheetah/hopper/walker2d-m} (medium): Collected by a policy with moderate performance, typically reaching around one-third of expert returns. These datasets represent structured but suboptimal behavior.
\item \texttt{halfcheetah/hopper/walker2d-m-r} (medium-replay): Contains the replay buffer of the mediocre SAC policy. It includes a wide range of off-policy transitions, many of which are suboptimal or noisy.
\item \texttt{halfcheetah/hopper/walker2d-m-e} (medium-expert): A 50-50 mixture of medium and expert trajectories. These datasets are designed to test whether algorithms can leverage near-optimal data when it is partially present.
\end{itemize}
The AntMaze environments involve a quadruped ant navigating through a 2D maze using sparse goal-based rewards. The agent has a 29-dimensional state space and an 8-dimensional action space, corresponding to joint positions, velocities, and target location encoding. The tasks are particularly challenging due to long-horizon planning and sparse supervision.
\begin{itemize}[leftmargin=1.5em, labelsep=0.5em]
\item \texttt{antmaze-u} (umaze): A small maze where the agent must reach a fixed goal location using sparse rewards. The environment is relatively easy due to short trajectories.
\item \texttt{antmaze-u-d} (umaze-diverse): Similar to \texttt{umaze}, but with broader trajectory diversity collected from random exploration.
\item \texttt{antmaze-m-p} (medium-play): A medium-sized maze where data is collected via a play policy. The task is harder due to longer horizons and sparse goal rewards.
\item \texttt{antmaze-m-d} (medium-diverse): Features more diverse and noisy behavior than \texttt{medium-play}, increasing exploration coverage but decreasing consistency.
\item \texttt{antmaze-l-p} (large-play): A large maze with random play data. The agent must navigate long distances, making the task especially difficult under sparse reward signals.
\item \texttt{antmaze-l-d} (large-diverse): Similar to \texttt{large-play}, but with broader and more varied behavior. It is one of the most challenging offline datasets due to the size of the environment and variability in data.
\end{itemize}
OGBench not only substantially extends the original AntMaze environment provided by the D4RL benchmark, but also introduces more challenging tasks, such as humanoid control and object manipulation. We elaborate on our selected environments below.
\begin{itemize}[leftmargin=1.5em, labelsep=0.5em]
\item \texttt{antmaze-giant-navigate}: An 8-DoF ant agent needs to reach a goal location in a 2-D maze, the size of which is substantially larger than those of D4RL datasets.
\item \texttt{humanoid-medium/large-navigate}: This task involves full-body control of a 21-DoF Humanoid agent, which requires long-horizon reasoning.
\item \texttt{antsoccer-arena-navigate}: This task involves controlling an ant agent to dribble a soccer ball. The agent is required to approach the ball and dribble it to random locations in an arena.
\item \texttt{cube-single/double-play}: This task involves pick-and-place manipulation of several different cubes. The agent is required to complete tasks by moving, stacking, swapping, or permuting cubes. The options "single" and "double" refer to the number of cubes.
\item \texttt{scene-play}: The agent's goal to manipulate the two buttons to determine the statuses of a window and a drawer to finish a specific task, which requires sequential reasoning.
\item \texttt{puzzle-3$\times$3/4$\times$4-play}: The goal is to solve a "light-out" puzzle with a robot arm. At each step, the agent can press a button to change the states of the pressed button and its neighbors. We select $3 \times 3$ and $4 \times 4$ as the puzzle size.
\end{itemize}
