\section{Psedocode of VGF}
\label{sec_code}
\begin{figure}[ht]
\centering
\begin{spacing}{0.9}
\begin{python}
import jax
import jax.numpy as jnp
def rbf_kernel(X, Y, sigma=None):
 """X: [B, n, d], Y: [B, m, d], returns K_XY: [B, n, m]"""
 X2 = jnp.sum(X * X, axis=-1, keepdims=True) 
 Y2 = jnp.sum(Y * Y, axis=-1, keepdims=True).transpose(0, 2, 1) 
 XY = jnp.matmul(X, Y.transpose(0, 2, 1)) 
 dnorm2 = X2 + Y2 - 2.0 * XY 
 dnorm2 = jnp.maximum(dnorm2, 0.0)
 if sigma is None:
 # median heuristic per batch
 h = jnp.median(dnorm2, axis=(1,2)) 
 h /= (2.0 * jnp.log(X.shape[1] + 1.0)) 
 sigma_val = jnp.sqrt(jnp.maximum(h, 1e-12)) 
 sigma_val = sigma_val[:, None, None]
 else:
 sigma_val = jnp.asarray(sigma)
 if sigma_val.ndim == 0:
 sigma_val = jnp.broadcast_to(sigma_val, (X.shape[0], 1, 1))
 gamma = 1.0 / (1e-6 + 2.0 * (sigma_val ** 2))
 K_XY = jnp.exp(-gamma * dnorm2) 
 return K_XY
class VGF:
 def __init__(self, q, alpha, optimizer):
 self.q = q
 self.alpha = alpha
 self.optim = optimizer
 self.opt_state = None
 def init(self, particles):
 self.opt_state = self.optim.init(particles)
 return particles, self.opt_state
 def phi(self, obs, particles):
 # obs: [B, D], particles: [B, N, D]
 # score terms
 def sum_q(action):
 obs_flatten = obs.reshape(-1, obs.shape[-1]) 
 action_flatten = action.reshape(-1, action.shape[-1]) 
 qs = self.q(obs_flatten, action_flatten)
 q = jnp.mean(qs, axis=0)
 return jnp.sum(q)
 score = jax.grad(sum_q)(particles) 
 # kernel terms
 particles_stop = jax.lax.stop_gradient(particles)
 K_xx = rbf_kernel(particles, particles_stop) 
 def sum_K(x):
 return jnp.sum(rbf_kernel(x, particles_stop))
 grad_q = jax.lax.stop_gradient(K_xx) @ score
 grad_K = -jax.grad(sum_K)(particles) 
 phi_val = (grad_q / self.alpha + grad_K) / particles.shape[1]
 return phi_val 
 def step(self, obs, particles, opt_s):
 grads = self.phi(obs, particles)
 updates, new_opt_s = self.optim.update(-grads, opt_s, particles)
 new_particles = optax.apply_updates(particles, updates)
 return new_particles, new_opt_s
\end{python}
\end{spacing}
