\section{Derivation of Lemma \ref{lemma:DPO}}\label{proof:dpo}
In this section, we provide the proof to derive the step-level DPO objective. For each $\mathbf{x}_{0:T}$, we have the following relationships between the reward and value functions:
\begin{flalign}
 &Q_{\pi_{\mathrm{pre}}}(s_t, a_t)=R(s_t, a_t)+V_{\pi_{\mathrm{pre}}}(s_{t+1}),\nonumber
 &A_{\pi_{\mathrm{pre}}}(s_t, a_t) = Q_{\pi_{\mathrm{pre}}}(s_t, a_t) - V_{\pi_{\mathrm{pre}}}(s_t).\nonumber
\end{flalign}
It then follows that
\begin{align}\label{eq:reward1}
r(\mathbf{x}_{0})
&= \sum_{t=0}^{T-1} R(s_t,a_t)\nonumber
&= \sum_{t=0}^{T-1} Q_{\pi_{\mathrm{pre}}}(s_t, a_t)-V_{\pi_{\mathrm{pre}}}(s_{t+1})\nonumber
&= V_{\pi_{\mathrm{pre}}}(s_0)+\sum_{t=0}^{T-1}
 \bigl(
 Q_{\pi_{\mathrm{pre}}}(s_t, a_t) - V_{\pi_{\mathrm{pre}}}(s_t)\bigr)-V_{\pi_{\mathrm{pre}}}(s_{T}
 ) \nonumber
&= V_{\pi_{\mathrm{pre}}}(s_0)
 + \sum_{t=0}^{T-1} A_{\pi_{\mathrm{pre}}}(s_t, a_t),
\end{align}
where the first equality is due to the definition of reward function $R$ and the last equality is due to $ V_{\pi_{\mathrm{pre}}}(s_T) = 0$.
According to the BT model, we have that
\begin{flalign}
 p_{BT}(\mathbf{x}_0^w\succ \mathbf{x}_0^l)=\sigma(r(\mathbf{x}_0^w)-r(\mathbf{x}_0^l)).\nonumber
\end{flalign}
Based on the BT model and Eq.~\eqref{eq:reward1}, we can write the loss as
\begin{flalign}
 -&\mathbb E_{(\mathbf{x}_0^w,\mathbf{x}_0^l)\sim \mathcal D}\log\sigma\left(r(\mathbf{x}_0^w)-r(\mathbf{x}_0^l)\right)\nonumber
 =&-\mathbb E_{(\mathbf{x}_0^w,\mathbf{x}_0^l)\sim \mathcal D}\log\sigma\left(\mathbb E_{\mathbf{x}_{0:T}^w\sim q(\mathbf{x}_{0:T}^w|\mathbf{x}_{0}^w), \mathbf{x}_{0:T}^l\sim q(\mathbf{x}_{0:T}^l|\mathbf{x}_{0}^l)}[r(\mathbf{x}_0^w)-r(\mathbf{x}_0^l)]\right)\nonumber
 =&-\mathbb E_{(\mathbf{x}_0^w,\mathbf{x}_0^l)\sim \mathcal D}\log\sigma\Bigg(\mathbb E_{\mathbf{x}_{0:T}^w\sim q(\mathbf{x}_{0:T}^w|\mathbf{x}_{0}^w), \mathbf{x}_{0:T}^l\sim q(\mathbf{x}_{0:T}^l|\mathbf{x}_{0}^l)}\Bigg[V_{\pi_{\mathrm{pre}}}(s_0^w)
 + \sum_{t=0}^{T-1} A_{\pi_{\mathrm{pre}}}(s_t^w, a_t^w)\nonumber
 &-V_{\pi_{\mathrm{pre}}}(s_0^l)
 - \sum_{t=0}^{T-1} A_{\pi_{\mathrm{pre}}}(s_t^l, a_t^l)\Bigg]\Bigg).
\end{flalign}
Similar to \cite{wallace2024diffusion}, we remove the $V_{\pi_{\mathrm{pre}}}(s_0^w), V_{\pi_{\mathrm{pre}}}(s_0^l)$ terms since they are constant and obtain the following objective
\begin{flalign}\label{eq:loss1}
 &-\mathbb E_{(\mathbf{x}_0^w,\mathbf{x}_0^l)\sim \mathcal D}\log\sigma\Bigg(\mathbb E_{\mathbf{x}_{0:T}^w\sim q(\mathbf{x}_{0:T}^w|\mathbf{x}_{0}^w), \mathbf{x}_{0:T}^l\sim q(\mathbf{x}_{0:T}^l|\mathbf{x}_{0}^l)}\Bigg[ \sum_{t=0}^{T-1} A_{\pi_{\mathrm{pre}}}(s_t^w, a_t^w)- \sum_{t=0}^{T-1} A_{\pi_{\mathrm{pre}}}(s_t^l, a_t^l)\Bigg]\Bigg)\nonumber
 &=-\mathbb E_{(\mathbf{x}_0^w,\mathbf{x}_0^l)\sim \mathcal D}\log\sigma\Bigg(T\mathbb E_{t\sim \mathcal{U}(0,T-1), \mathbf{x}_{0:T}^w\sim q(\mathbf{x}_{0:T}^w|\mathbf{x}_{0}^w), \mathbf{x}_{0:T}^l\sim q(\mathbf{x}_{0:T}^l|\mathbf{x}_{0}^l)}\Bigg[ A_{\pi_{\mathrm{pre}}}(s_t^w, a_t^w)-  A_{\pi_{\mathrm{pre}}}(s_t^l, a_t^l)\Bigg]\Bigg).
\end{flalign}
Moreover, based on the definition of value functions and Lemma \ref{lemma1}, we can show that 
\begin{flalign}
 A_{\pi_{\mathrm{pre}}}(s_t^w, a_t^w)&=Q_{\pi_{\mathrm{pre}}}(s_t^w, a_t^w)- V_{\pi_{\mathrm{pre}}}(s_t^w)\nonumber
 &=Q_{\pi_{\mathrm{pre}}}(s_t^w, a_t^w)- \mathbb E_{a\sim \pi_{\mathrm{pre}}}[Q_{\pi_{\mathrm{pre}}}(s_t^w, a)]\nonumber
 &=\lambda \log\left(\frac{p_\theta(\mathbf{x}_{T-t-1}^w|\mathbf{x}_{T-t}^w)}{p_{\text{pre}}(\mathbf{x}_{T-t-1}^w|\mathbf{x}_{T-t}^w)}\right)+\lambda\log(Z(\mathbf{x}_{T-t}^w)) \nonumber
 &-\mathbb E_{\mathbf{x}_{T-t-1}^w\sim \pi_{\text{pre}}}\left[\lambda \log\left(\frac{p_\theta(\mathbf{x}_{T-t-1}^w|\mathbf{x}_{T-t}^w)}{p_{\text{pre}}(\mathbf{x}_{T-t-1}^w|\mathbf{x}_{T-t}^w)}\right)\right]-\lambda\log(Z(\mathbf{x}_{T-t}^w)) \nonumber
 &=\lambda \log\left(\frac{p_\theta(\mathbf{x}_{T-t-1}^w|\mathbf{x}_{T-t}^w)}{p_{\text{pre}}(\mathbf{x}_{T-t-1}^w|\mathbf{x}_{T-t}^w)}\right)+\lambda\mathbb{D}_{\mathrm{KL}}(p_{\text{pre}}(\cdot|\mathbf{x}_{T-t}^w)||p_{\theta}(\cdot|\mathbf{x}_{T-t}^w)).
\end{flalign}
By Jensen’s inequality, the objective in Eq.~\eqref{eq:loss1} can be upper bounded by 
\begin{flalign}\label{eq:dpo3}
 -&\mathbb E_{(\mathbf{x}_0^w,\mathbf{x}_0^l)\sim \mathcal D}\log\sigma\Bigg(T\mathbb E_{t\sim \mathcal{U}(0,T-1), \mathbf{x}_{0:T}^w\sim q(\mathbf{x}_{0:T}^w|\mathbf{x}_{0}^w), \mathbf{x}_{0:T}^l\sim q(\mathbf{x}_{0:T}^l|\mathbf{x}_{0}^l)}\Bigg[ A_{\pi_{\mathrm{pre}}}(s_t^w, a_t^w)-  A_{\pi_{\mathrm{pre}}}(s_t^l, a_t^l)\Bigg]\Bigg)\nonumber
 \le&  -\mathbb E_{t\sim \mathcal{U}(0,T-1), (\mathbf{x}_0^w,\mathbf{x}_0^l)\sim \mathcal D, \mathbf{x}_{T-t}^w\sim q(\mathbf{x}_{T-t}^w|\mathbf{x}_{0}^w), \mathbf{x}_{T-t}^l\sim q(\mathbf{x}_{T-t}^l|\mathbf{x}_{0}^l) }\nonumber
 &\log\sigma\Bigg(T\mathbb E_{ \mathbf{x}_{T-t-1}^w\sim q(\mathbf{x}_{T-t-1}^w|\mathbf{x}_{T-t}^w, \mathbf{x}_{0}^w), \mathbf{x}_{T-t-1}^l\sim q(\mathbf{x}_{T-t-1}^l|\mathbf{x}_{T-t}^l, \mathbf{x}_{0}^l)}\Bigg[ A_{\pi_{\mathrm{pre}}}(s_t^w, a_t^w)-  A_{\pi_{\mathrm{pre}}}(s_t^l, a_t^l)\Bigg]\Bigg).
\end{flalign}
It can be further shown that
\begin{flalign}
 \mathbb E&_{\mathbf{x}_{T-t-1}^w\sim q(\mathbf{x}_{T-t-1}^w|\mathbf{x}_{T-t}^w, \mathbf{x}_{0}^w), \mathbf{x}_{T-t-1}^l\sim q(\mathbf{x}_{T-t-1}^l|\mathbf{x}_{T-t}^l, \mathbf{x}_{0}^l)}\Bigg[ A_{\pi_{\mathrm{pre}}}(s_t^w, a_t^w)\Bigg]\nonumber
 =&\lambda\mathbb{D}_{\mathrm{KL}}(p_{\text{pre}}(\cdot|\mathbf{x}_{T-t}^w)||p_{\theta}(\cdot|\mathbf{x}_{T-t}^w))\nonumber
 &+\lambda \mathbb E_{\mathbf{x}_{T-t-1}^w\sim q(\mathbf{x}_{T-t-1}^w|\mathbf{x}_{T-t}^w, \mathbf{x}_{0}^w), \mathbf{x}_{T-t-1}^l\sim q(\mathbf{x}_{T-t-1}^l|\mathbf{x}_{T-t}^l, \mathbf{x}_{0}^l)}\Bigg[\log\left(\frac{p_\theta(\mathbf{x}_{T-t-1}^w|\mathbf{x}_{T-t}^w)}{p_{\text{pre}}(\mathbf{x}_{T-t-1}^w|\mathbf{x}_{T-t}^w)}\right)\Bigg]\nonumber
 =&\lambda\mathbb{D}_{\mathrm{KL}}(p_{\text{pre}}(\cdot|\mathbf{x}_{T-t}^w)||p_{\theta}(\cdot|\mathbf{x}_{T-t}^w))-\lambda\mathbb{D}_{\mathrm{KL}}(q(\cdot|\mathbf{x}_{T-t}^w, \mathbf{x}_{0}^w )||\pi_{\theta}(\cdot|\mathbf{x}_{T-t}^w))+\lambda\mathbb{D}_{\mathrm{KL}}(q(\cdot|\mathbf{x}_{T-t}^w, \mathbf{x}_{0}^w)||p_{\text{pre}}(\cdot|\mathbf{x}_{T-t}^w)).
\end{flalign}
Applying the same analysis to $A_{\pi_{\mathrm{pre}}}(s_t^l, a_t^l)$ and plugging the results to Eq.~\eqref{eq:dpo3}, we then  can get the following objective:
\begin{flalign}
 -&\mathbb E_{t\sim \mathcal{U}(0,T-1), (\mathbf{x}_0^w,\mathbf{x}_0^l)\sim \mathcal D, \mathbf{x}_{T-t}^w\sim q(\mathbf{x}_{T-t}^w|\mathbf{x}_{0}^w), \mathbf{x}_{T-t}^l\sim q(\mathbf{x}_{T-t}^l|\mathbf{x}_{0}^l) }\nonumber
 &\log\sigma\Bigg(T\mathbb E_{ \mathbf{x}_{T-t-1}^w\sim q(\mathbf{x}_{T-t-1}^w|\mathbf{x}_{T-t}^w, \mathbf{x}_{0}^w), \mathbf{x}_{T-t-1}^l\sim q(\mathbf{x}_{T-t-1}^l|\mathbf{x}_{T-t}^l, \mathbf{x}_{0}^l)}\Bigg[ A_{\pi_{\mathrm{pre}}}(s_t^w, a_t^w)-  A_{\pi_{\mathrm{pre}}}(s_t^l, a_t^l)\Bigg]\Bigg)\nonumber
 =&\mathbb E_{t\sim \mathcal{U}(0,T-1), (\mathbf{x}_0^w,\mathbf{x}_0^l)\sim \mathcal D, \mathbf{x}_{T-t}^w\sim q(\mathbf{x}_{T-t}^w|\mathbf{x}_{0}^w), \mathbf{x}_{T-t}^l\sim q(\mathbf{x}_{T-t}^l|\mathbf{x}_{0}^l) }\nonumber
 &\log\sigma\Bigg(T\lambda\Bigg(-\mathbb{D}_{\mathrm{KL}}(q(\cdot|\mathbf{x}_{T-t}^w, \mathbf{x}_{0}^w )||\pi_{\theta}(\cdot|\mathbf{x}_{T-t}^w))+\mathbb{D}_{\mathrm{KL}}(q(\cdot|\mathbf{x}_{T-t}^l, \mathbf{x}_{0}^l )||\pi_{\theta}(\cdot|\mathbf{x}_{T-t}^l))\nonumber
 &+\mathbb{D}_{\mathrm{KL}}(q(\cdot|\mathbf{x}_{T-t}^w, \mathbf{x}_{0}^w)||p_{\text{pre}}(\cdot|\mathbf{x}_{T-t}^w))-\mathbb{D}_{\mathrm{KL}}(q(\cdot|\mathbf{x}_{T-t}^l, \mathbf{x}_{0}^l)||p_{\text{pre}}(\cdot|\mathbf{x}_{T-t}^l))\nonumber
 &+\mathbb{D}_{\mathrm{KL}}(p_{\text{pre}}(\cdot|\mathbf{x}_{T-t}^w)||p_{\theta}(\cdot|\mathbf{x}_{T-t}^w))-\mathbb{D}_{\mathrm{KL}}(p_{\text{pre}}(\cdot|\mathbf{x}_{T-t}^l)||p_{\theta}(\cdot|\mathbf{x}_{T-t}^l))\Bigg)\Bigg)
\end{flalign}
By the Gaussian parameterization of the reverse process \cite{wallace2024diffusion}, this objective can be simplified to 
\begin{flalign}
L_{SDPO}=&-\mathbb{E}_{(\mathbf{x}_0^w,\mathbf{x}_0^l)\sim \mathcal{D},\, t\sim \mathcal{U}(1,T),\,
 \mathbf{x}_t^w\sim q(\mathbf{x}_t^w \mid \mathbf{x}_0^w),\, \mathbf{x}_t^l\sim q(\mathbf{x}_t^l \mid \mathbf{x}_0^l)}\nonumber
 & 
 \Big[
 \log \sigma\Big( -\lambda T \omega (\lambda_t)\Big(
 \|\epsilon^w - \epsilon_\theta(\mathbf{x}_t^w,t)\|_2^2
 - \|\epsilon^w - \epsilon_{\mathrm{pre}}(\mathbf{x}_t^w,t)\|_2^2 \nonumber
&
 - \big(
 \|\epsilon^l - \epsilon_\theta(\mathbf{x}_t^l,t)\|_2^2
 - \|\epsilon^l - \epsilon_{\mathrm{pre}}(\mathbf{x}_t^l,t)\|_2^2
 \big)\nonumber
 & - \big(
 \|\epsilon_\theta(\mathbf{x}_t^w,t)-\epsilon_{\mathrm{pre}}(\mathbf{x}_t^w,t)\|_2^2
 - \|\epsilon_{\theta}(\mathbf{x}_t^l,t) - \epsilon_{\mathrm{pre}}(\mathbf{x}_t^l,t)\|_2^2
 \big)
 \Big)
 \Big)
 \Big], 
\end{flalign}
where $\mathbf{x}_{0}^w$ and $\mathbf{x}_{0}^l$ denote the winning and losing samples, respectively and  we have that
\[
\mathbf{x}_t^{*} = \sqrt{\bar{\alpha}_t}\,\mathbf{x}_0^{*}
+ \sqrt{1-\bar{\alpha}_t}\,\epsilon^{*}, 
\qquad
\epsilon^{*} \sim \mathcal{N}(\mathbf{0},\mathbf{I}),
\]
which is drawn from \(q(\mathbf{x}_t^{*} \mid \mathbf{x}_0^{*})\), and the quantity \(\lambda_t = \bar{\alpha}_t / (1-\bar{\alpha}_t)\) is the signal-to-noise ratio. The function $\omega(\lambda_t)$ is a weighting function (often taken to be constant in practice~\cite{ho2020denoising,kingma2021variational}). $\epsilon_*(\mathbf{x}_t,t)$ is a function approximator that predicts $\epsilon$ from $\mathbf{x}_t$ such that 
\begin{flalign}
 \mu_*(\mathbf{x}_t,t)
 = \frac{1}{\sqrt{\alpha_t}}
 \left(
 \mathbf{x}_t
 - \frac{\beta_t}{\sqrt{1-\bar{\alpha}_t}}
 \,\epsilon_*(\mathbf{x}_t,t)
 \right).
\end{flalign}
\section{Proof of Lemma \ref{lemma1}}\label{proof:lemma}
\begin{proof}
We can first define that
\begin{align}
\mathcal{J}(\pi_\theta; s_t)
&= \mathbb{E}_{z \sim \pi_\theta(\cdot \mid s_t)}
 \left[
 Q_{\pi_{\mathrm{pre}}}(s_t, z) - V_{\pi_{\mathrm{pre}}}(s_t)
 - \lambda
 \log
 \frac{
 \pi_\theta(z \mid s_t)
 }{
 \pi_{\mathrm{pre}}(z \mid s_t)
 }
 \right] \nonumber 
&= \lambda
 \mathbb{E}_{z \sim \pi_\theta(\cdot \mid s_t)}
 \left[
 \log
 \frac{
 \pi_{\mathrm{pre}}(z \mid s_t)
 \exp\bigl(Q_{\pi_{\mathrm{pre}}}(s_t, z)/\lambda\bigr)
 }{
 \pi_\theta(z \mid s_t)
 }
 \right]
 - V_{\pi_{\mathrm{pre}}}(s_t),\nonumber
\end{align}
where we have that $
 Z(s_t)
  = \int
 \pi_{\mathrm{ref}}(z \mid s_t)
 \exp\bigl(Q_{\pi_{\mathrm{ref}}}(s_t, z)/\lambda\bigr)
 \, dz.
$
The optimal solution of Eq.~\eqref{eq:rlhf3} can be obtained by optimizing $\mathcal{J}(\pi_\theta; s_t)$ for each $s_t$. We can further rewrite $\mathcal{J}(\pi_\theta; s_t)$ as:
\begin{align}
\mathcal{J}(\pi_\theta; s_t)
&= - \lambda
 \mathbb D_{\mathrm{KL}}\left(
 \pi_\theta(\cdot \mid s_t)
 \,\middle\|\,
 \frac{
 \pi_{\mathrm{pre}}(\cdot \mid s_t)
 \exp\bigl(Q_{\pi_{\mathrm{pre}}}(s_t, \cdot)/\lambda\bigr)
 }{
 Z(s_t)
 }
 \right)
 - V_{\pi_{\mathrm{pre}}}(s_t)
 + \lambda \log Z(s_t).
\end{align}
Thus, we can find the optimal solution:
\begin{flalign}
\pi_\theta^\star(z \mid s_t)
  = \frac{
 \pi_{\mathrm{ref}}(z \mid s_t)
 \exp\bigl(Q_{\pi_{\mathrm{pre}}}(s_t, z)/\lambda\bigr)
 }{
 Z(s_t)
 }.
\end{flalign}
This completes the proof.
\end{proof}
\section{Proof of Theorem \ref{theorem1}}\label{proof:the}
\begin{proof}
Based on Lemma \ref{lemma1}, we can show that for each $1\le i\le M$, we have that
\begin{flalign}
\pi_i(z \mid s_t)
  = \frac{
 \pi_{\mathrm{pre}}(z \mid s_t)
 \exp\bigl(Q_{\pi_{\mathrm{pre}}}^i(s_t, z)/\lambda\bigr)
 }{
 Z_i(s_t)
 },\nonumber
\end{flalign}
where $Q_{\pi_{\mathrm{pre}}}^i$ is the state-action value function with reward $r_i$ and $
 Z_i(s_t)
  = \int
 \pi_{\mathrm{ref}}(z \mid s_t)
 \exp\bigl(Q^i_{\pi_{\mathrm{pre}}}(s_t, z)/\lambda\bigr)
 \, dz$. Moreover, we can further show that
\begin{flalign}\label{eq:piw}
\pi_w(z \mid s_t)
  = \frac{
 \pi_{\mathrm{pre}}(z \mid s_t)
 \exp\bigl(Q_{\pi_{\mathrm{pre}}}^w(s_t, z)/\lambda\bigr)
 }{
 Z_w(s_t)
 },
\end{flalign}
where $Q_{\pi_{\mathrm{pre}}}^w$ is the state-action value function with reward $r_w$ and $
 Z_w(s_t)
  = \int
 \pi_{\mathrm{ref}}(z \mid s_t)
 \exp\bigl(Q^w_{\pi_{\mathrm{pre}}}(s_t, z)/\lambda\bigr)
 \, dz.$
For the state-action function, we can show that 
\begin{flalign}
 Q^w_{\pi_{\mathrm{pre}}}(s_t, z)&=\mathbb{E}_{\pi_{\mathrm{pre}}}\bigl[ r^w(s_T) \mid s_t, a_t \bigr]\nonumber
 &=\mathbb{E}_{\pi_{\mathrm{pre}}}\left[ \sum_{i=1}^Mw_ir_i(s_T) \mid s_t, a_t \right]\nonumber
 &=\sum_{i=1}^Mw_i\mathbb{E}_{\pi_{\mathrm{pre}}}\bigl[ r_i(s_T) \mid s_t, a_t \bigr]\nonumber
 &=\sum_{i=1}^Mw_iQ^i_{\pi_{\mathrm{pre}}}(s_t, z).
\end{flalign}
As a result, we can show that
\begin{flalign}
 \exp\bigl(Q_{\pi_{\mathrm{pre}}}^w(s_t, z)/\lambda\bigr)&=\exp\left(\sum_{i=1}^Mw_iQ^i_{\pi_{\mathrm{pre}}}(s_t, z)/\lambda\right)\nonumber
 &=\prod_{i=1}^M\exp\bigl(w_iQ^i_{\pi_{\mathrm{pre}}}(s_t, z)/\lambda\bigr)\nonumber
 &=\prod_{i=1}^M\exp\bigl(Q^i_{\pi_{\mathrm{pre}}}(s_t, z)/\lambda\bigr)^{w_i}\nonumber
 &=\frac{\prod_{i=1}^M \pi_i^{w_i}(z \mid s_t) Z_i^{w_i}(s_t)}{{\pi_{\mathrm{pre}}}}.\nonumber
\end{flalign}
Plugging the above equation into Eq.~\eqref{eq:piw}, it can be shown that 
\begin{flalign}
 \pi_w(z \mid s_t)=\frac{ \prod_{i=1}^M \pi_i^{w_i}(z \mid s_t)}{\int \prod_{i=1}^M \pi_i^{w_i}(z' \mid s_t) dz'}.\nonumber
\end{flalign}
Based on the definition that $\pi_i(a_t|s_t)=p_i(\mathbf{x}_{T-t-1}|\mathbf{x}_{T-t})$ for $s_t=\mathbf{x}_{T-t}$ and $a_t=\mathbf{x}_{T-t-1}$, we know that 
\begin{flalign}
{p}_w(\mathbf{x}_{t-1}\mid \mathbf{x}_{t})
  =
  \frac{
 \prod_{i=1}^M {p}_i^{w_i}(\mathbf{x}_{t-1}\mid \mathbf{x}_{t})
  }{
 \displaystyle
 \int
 \prod_{i=1}^M {p}_i^{w_i}(\mathbf{x}'_{t-1}\mid \mathbf{x}_{t}) \, d\mathbf{x}'_{t-1}\nonumber
  },
\end{flalign}
where each ${p}_i(\mathbf{x}_{t-1}\mid \mathbf{x}_{t})  $ follows the Gaussian distribution with mean and variance $(\mu_i, \sigma_i^2) $. Thus, ${p}_w(\mathbf{x}_{t-1}\mid \mathbf{x}_{t})$ is also a Gaussian distribution, and ${p}_w(\mathbf{x}_{t-1}\mid \mathbf{x}_{t}) \propto \exp\left(-\sum_{i=1}^M\frac{w_i}{2\sigma_i^2}\|\mathbf{x}_{t-1}-\mu_i\|^2\right)$. We can then derive its mean and variance as: 
\begin{flalign}
 &\sigma_w^2= \left(\sum_{i=1}^M \frac{w_i}{\sigma_i^2}\right)^{-1},\nonumber
 &\mu_{w}=\sigma_w^2\sum_{i=1}^M \frac{w_i}{\sigma_i^2}\,\mu_i.\nonumber
\end{flalign}
This completes the proof.
\end{proof}
\section{Approximated Errors in Existing Denoising-Time Works}\label{approxi}
\textbf{DB-MPA~\cite{cheng2025diffusion}} considers a stochastic differential equation (SDE) formulation:
\[
\mathrm{d}\mathbf{x}_t = f^{\mathrm{pre}}(\mathbf{x}_t,t)\,\mathrm{d}t + \sigma(t)\,\mathrm{d}w_t,\qquad \forall\, t\in[T,0],
\]
where $\sigma(t), \beta(t)$ represents two fixed scalar functions, $w_t$ is a standard Wiener
process,  $p_t$ is a marginal distribution and  $f^{\mathrm{pre}}(\mathbf{x}_t,t)$ denotes the term $$ f^{\mathrm{pre}}(\mathbf{x}_t,t)=
-\tfrac{1}{2}\beta(t)\,\mathbf{x}_t \;-\; \beta(t)\,\nabla_{\mathbf{x}_t}\log p_t(\mathbf{x}_t).
$$
To maximize Eq.~\eqref{eq:rlhf1} with reward $r$, the SDE becomes 
\[
\mathrm{d}\mathbf{x}_t = f^{(r,\lambda)}(\mathbf{x}_t,t)\,\mathrm{d}t + \sigma(t)\,\mathrm{d}w_t,\qquad \forall\, t\in[T,0],
\]
where 
\[
f^{(r,\lambda)}(\mathbf{x}_t,t) = f^{\mathrm{pre}}(\mathbf{x}_t,t) + u^{(r,\lambda)}(\mathbf{x}_t,t),
\]
and
\[
u^{(r,\lambda)}(\mathbf{x}_t,t)
= \nabla_{\mathbf{x}_t} \log \mathbb{E}_{\mathbf{x}_0 \sim p^{\mathrm{pre}}_{0|t}(\cdot \mid \mathbf{x}_t)}
\left[ \exp\left( \frac{r(\mathbf{x}_0)}{\lambda} \right) \right].
\]
Let $\Delta^{(r_i,\lambda)}(\mathbf{x},t)=u^{(r,\lambda)}(\mathbf{x}_t,t)- \nabla_{\mathbf{x}_t}  \mathbb{E}_{\mathbf{x}_0 \sim p^{\mathrm{pre}}_{0|t}(\cdot \mid \mathbf{x}_t)}
\left[  \frac{r(\mathbf{x}_0)}{\lambda} \right]$, for each $r^w=\sum_{i=1}^Mw_ir_i$, it can be shown  that with the identical variance, 
\begin{flalign}\label{eq:DB}
 f^{(r^w,\lambda)}(\mathbf{x}_t,t)
= \sum_{i=1}^M w_i\, f^{(r_i,\lambda)}(\mathbf{x}_t,t)
+ \Bigl(\Delta^{(r^w,\lambda)}(\mathbf{x}_t,t) - \sum_{i=1}^M w_i\,\Delta^{(r_i,\lambda)}(\mathbf{x}_t,t)\Bigr).
\end{flalign}
To get the denoising-time solution, DB-MPA ignores the last two terms in Eq.~\eqref{eq:DB} and gets $f^{(r^w,\lambda)}(\mathbf{x}_t,t)\approx  \sum_{i=1}^M w_i\, f^{(r_i,\lambda)}(\mathbf{x}_t,t).$
\textbf{DERADIFF~\cite{anonymous2025deradiff}} studies the RL fine-tuning problem in Eq.~\eqref{eq:rlhf1}. Similar to our Lemma \ref{lemma1} and Theorem \ref{theorem1}, the optimal solution should satisfy that 
\begin{flalign}
 p_w(\mathbf{x}_0)=\frac{ \prod_{i=1}^M p_i^{w_i}(\mathbf{x}_0)}{\int \prod_{i=1}^M p_i^{w_i}(\mathbf{x}_0') d\mathbf{x}_0'}.
\end{flalign}
However, it is hard to track the marginal distribution of $\mathbf{x}_0$, thus DERADIFF conducts a stepwise approximation for any $t$ without any theoretical justification:
\begin{flalign}
 p_w(\mathbf{x}_{t-1}|\mathbf{x}_t)=\frac{ \prod_{i=1}^M p_i^{w_i}(\mathbf{x}_{t-1}|\mathbf{x}_t)}{\int \prod_{i=1}^M p_i^{w_i}(\mathbf{x}_{t-1}'|\mathbf{x}_t) d\mathbf{x}_{t-1}'}.
\end{flalign}
