\section{Theoretical Derivations}
\subsection{The Loss Derivation of the Average Divergence Network}
\label{appdx::loss_avg_div}
The ground-truth average divergence is defined as
\begin{equation}
 \delta(\boldsymbol{s}, \boldsymbol{a}_t, r, t)
 =
 \frac{1}{t - r}
 \int_{r}^{t}
 \nabla \cdot \boldsymbol{v}_{\theta}(\boldsymbol{s}, \boldsymbol{a}_{\tau}, \tau)
 \,\mathrm{d}\tau .
\end{equation}
Multiplying both sides by $t-r$ and differentiating with respect to $t$ yield the identity
\begin{equation}
\label{eq::avgdiv_identity}
 \delta(\boldsymbol{s}, \boldsymbol{a}_t, r, t)
 =
 \nabla \cdot \boldsymbol{v}_{\theta}(\boldsymbol{s}, \boldsymbol{a}_t, t)
 -
 (t-r)\frac{\mathrm{d}}{\mathrm{d}t}
 \delta(\boldsymbol{s}, \boldsymbol{a}_t, r, t),
\end{equation}
where the total time derivative is given by
\begin{equation}
 \frac{\mathrm{d}}{\mathrm{d}t}\delta(\boldsymbol{s}, \boldsymbol{a}_t, r, t)
 =
 \boldsymbol{v}_{\theta}(\boldsymbol{s}, \boldsymbol{a}_t, t)\,\partial_{\boldsymbol{a}}\delta
 +
 \partial_t \delta .
\end{equation}
We take the right-hand side of Eq.~\eqref{eq::avgdiv_identity} as the training target for the
average divergence network $\delta_{\omega}$, leading to the objective
\begin{equation}
 \mathcal{L}(\omega)
 =
 \mathbb{E}_{\boldsymbol{s}, r, t, \boldsymbol{a}_t}
 \left\|
 \delta_{\omega}(\boldsymbol{s}, \boldsymbol{a}_t, r, t)
 -
 \operatorname{sg}(\delta_{\mathrm{tgt}})
 \right\|_2^2,
\end{equation}
with
\begin{equation}
 \delta_{\mathrm{tgt}}
 =
 \nabla \cdot \boldsymbol{v}_{\theta}(\boldsymbol{s}, \boldsymbol{a}_t, t)
 -
 (t - r)
 \left(
 \boldsymbol{v}_{\theta}(\boldsymbol{s}, \boldsymbol{a}_t, t)\,\partial_{\boldsymbol{a}}\delta
 +
 \partial_t \delta
 \right).
\end{equation}
In practice, the divergence term is replaced by its unbiased estimator, and the instantaneous
velocity is obtained from the average velocity network
$\boldsymbol{u}_{\theta}(\boldsymbol{s}, \boldsymbol{a}_t, r, t)$ by setting $r=t$.
The final training target therefore becomes
\begin{equation}
 \delta_{\mathrm{tgt}}
 =
 \widehat{\mathrm{div}}
 -
 (t - r)
 \left(
 \boldsymbol{u}_{\theta}(\boldsymbol{s}, \boldsymbol{a}_t, t, t)\,\partial_{\boldsymbol{a}}\delta
 +
 \partial_t \delta
 \right),
\end{equation}
where $\widehat{\mathrm{div}}$ denotes the Skilling--Hutchinson trace estimator
introduced in Eq.~\eqref{eq::div_estimation}.
\subsection{Rewriting the Conditional Distribution $\pi(\boldsymbol{a}_0 | \boldsymbol{a}_t, \boldsymbol{s})$}
\label{appdx::condition_distribution}
In this section, we derive an equivalent expression for the conditional distribution
$\pi(\boldsymbol{a}_0 | \boldsymbol{a}_t, \boldsymbol{s})$.
Specifically, we show that it can be written as
\begin{equation}
 \pi(\boldsymbol{a}_0 | \boldsymbol{a}_t, \boldsymbol{s})
 \propto
 \exp\!\left(\frac{1}{\alpha} Q(\boldsymbol{s}, \boldsymbol{a}_0)\right)
 \mathcal{N}\!\left(
 \boldsymbol{a}_0 \,\middle|\,
 \frac{\boldsymbol{a}_t}{1 - t},
 \left( \frac{t}{1 - t} \right)^2 \boldsymbol{I}
 \right).
\end{equation}
\begin{proof}
By Bayes' rule, we have
\begin{align}
 \pi(\boldsymbol{a}_0 | \boldsymbol{a}_t, \boldsymbol{s})
 &= \frac{
 \pi(\boldsymbol{a}_0 | \boldsymbol{s}) \,
 \pi(\boldsymbol{a}_t | \boldsymbol{a}_0)
 }{
 \pi(\boldsymbol{a}_t | \boldsymbol{s})
 } 
 &\propto
 \pi(\boldsymbol{a}_0 | \boldsymbol{s}) \,
 \pi(\boldsymbol{a}_t | \boldsymbol{a}_0),
 \label{eq::conditional_distribution_bayes}
\end{align}
where $\pi(\boldsymbol{a}_t | \boldsymbol{s})$ is a constant with respect to
$\boldsymbol{a}_0$.
Under the MaxEnt RL formulation, the target policy satisfies
\(
 \pi(\boldsymbol{a}_0 | \boldsymbol{s})
 =
 \frac{1}{Z(\boldsymbol{s})}
 \exp\!\left( \frac{1}{\alpha} Q(\boldsymbol{s}, \boldsymbol{a}_0) \right),
\)
where $Z(\boldsymbol{s})$ denotes the partition function.
Substituting this expression into
Eq.~\eqref{eq::conditional_distribution_bayes} yields
\begin{align}
 \pi(\boldsymbol{a}_0 | \boldsymbol{a}_t, \boldsymbol{s})
 &\propto
 \exp\!\left( \frac{1}{\alpha} Q(\boldsymbol{s}, \boldsymbol{a}_0) \right)
 \pi(\boldsymbol{a}_t | \boldsymbol{a}_0).
\end{align}
Recall that the forward interpolation process is defined as
\(
 \boldsymbol{a}_t = (1 - t)\boldsymbol{a}_0 + t \boldsymbol{a}_1,
\)
\(
 \boldsymbol{a}_1 \sim \mathcal{N}(\boldsymbol{0}, \boldsymbol{I}),
\)
which implies
\(
 \pi(\boldsymbol{a}_t | \boldsymbol{a}_0)
 =
 \mathcal{N}\!\left(
 \boldsymbol{a}_t \,\middle|\,
 (1 - t)\boldsymbol{a}_0,\,
 t^2 \boldsymbol{I}
 \right).
\)
Note that
\(
 \mathcal{N}\!\left(
 \boldsymbol{a}_t \,\middle|\,
 (1 - t)\boldsymbol{a}_0,\,
 t^2 \boldsymbol{I}
 \right)
 \propto
 \exp\!\left(
 -\frac{
 \left\lVert \boldsymbol{a}_t - (1 - t)\boldsymbol{a}_0 \right\rVert^2
 }{
 2t^2
 }
 \right),
\)
and
\(
 \mathcal{N}\!\left(
 \boldsymbol{a}_0 \,\middle|\,
 \frac{\boldsymbol{a}_t}{1 - t},\,
 \left( \frac{t}{1 - t} \right)^2 \boldsymbol{I}
 \right)
 \propto
 \exp\!\left(
 -\frac{
 \left\lVert
 \boldsymbol{a}_0 - \frac{\boldsymbol{a}_t}{1 - t}
 \right\rVert^2
 }{
 2\left( \frac{t}{1 - t} \right)^2
 }
 \right),
\)
we observe
\begin{equation}
 \mathcal{N}\!\left(
 \boldsymbol{a}_t \,\middle|\,
 (1 - t)\boldsymbol{a}_0,\,
 t^2 \boldsymbol{I}
 \right)
 \propto
 \mathcal{N}\!\left(
 \boldsymbol{a}_0 \,\middle|\,
 \frac{\boldsymbol{a}_t}{1 - t},\,
 \left( \frac{t}{1 - t} \right)^2 \boldsymbol{I}
 \right),
\end{equation}
where the proportionality holds up to a constant independent of
$\boldsymbol{a}_0$. Substituting this relation back into the conditional distribution completes the proof:
\begin{equation}
 \pi(\boldsymbol{a}_0 | \boldsymbol{a}_t, \boldsymbol{s})
 \propto
 \exp\!\left( \frac{1}{\alpha} Q(\boldsymbol{s}, \boldsymbol{a}_0) \right)
 \mathcal{N}\!\left(
 \boldsymbol{a}_0 \,\middle|\,
 \frac{\boldsymbol{a}_t}{1 - t},\,
 \left( \frac{t}{1 - t} \right)^2 \boldsymbol{I}
 \right).
\end{equation}
\end{proof}
\subsection{An Introduction to the Effective Sample Size of Self-Normalized Importance Sampling}
\label{appdx::ess}
Given a target distribution $p(\boldsymbol{x})$, a proposal distribution $q(\boldsymbol{x})$, and a target function $f(\boldsymbol{x})$, we aim to estimate the expectation $\mathbb{E}_{p}[f(\boldsymbol{x})]$. To this end, we compare the vanilla Monte Carlo (MC) estimator with the Self-Normalized Importance Sampling (SNIS) estimator:
\begin{equation}
 \hat{\mu}_{\mathrm{MC}} = \frac{1}{K} \sum_{i=1}^K f(\boldsymbol{x}_i), \quad \boldsymbol{x}_i \sim p,
\end{equation}
\begin{equation}
 \hat{\mu}_{\mathrm{SNIS}} = \sum_{i=1}^K \frac{w(\boldsymbol{x}_i)}{\sum_{j=1}^K w(\boldsymbol{x}_j)} f(\boldsymbol{x}_i), \quad \boldsymbol{x}_i \sim q,
\end{equation}
where $w(\boldsymbol{x}) = p(\boldsymbol{x})/q(\boldsymbol{x})$ denotes the importance weight. The efficiency of the SNIS estimator is typically quantified by the \emph{Effective Sample Size} (ESS) \cite{kong1992note,metelli2020importance}, which characterizes the number of i.i.d. samples from $p$ required to achieve the same estimation variance as $K$ samples from $q$. Formally, the ESS is asymptotically defined through the variance ratio:
\begin{equation}
 \mathrm{ESS}(p \parallel q) \approx K \frac{\mathrm{Var}(\hat{\mu}_{\mathrm{MC}})}{\mathrm{Var}(\hat{\mu}_{\mathrm{SNIS}})}.
\end{equation}
In practice, the ESS is commonly approximated using the Kish’s estimator \cite{kong1992note}:
\begin{equation}
 \widehat{\mathrm{ESS}}(p \parallel q) = \frac{\left(\sum_{i=1}^K w(\boldsymbol{x}_i)\right)^2}{\sum_{i=1}^K w^2(\boldsymbol{x}_i)}.
\end{equation}
This metric ranges from $1$ to $K$. It attains its maximum value $K$ when $q = p$, and degrades as the discrepancy between the proposal distribution and the target distribution increases, indicating higher estimation variance and reduced sampling efficiency.
\subsection{The Bias and Variance Analysis of the Adaptive Instantaneous Velocity Estimator}
\label{appdx::bias_var}
The ground-truth instantaneous velocity is given by:
\(
 \boldsymbol{v}_t(\boldsymbol{a}_t | \boldsymbol{s}) = \mathbb{E}_{\pi(\boldsymbol{a}_0 | \boldsymbol{a}_t, \boldsymbol{s})} \left[ \frac{\boldsymbol{a}_t - \boldsymbol{a}_0}{t} \right].
\)
We consider two self-normalized importance sampling (SNIS) estimators, $\hat{\boldsymbol{v}}^1_t$ and $\hat{\boldsymbol{v}}^2_t$, constructed using proposal distributions $q^1(\boldsymbol{a}_0)$ and $q^2(\boldsymbol{a}_0)$ with $K_1$ and $K_2$ samples, respectively. To leverage the complementary strengths of different proposals, we define a combined estimator as a linear combination of two SNIS estimators:
\begin{equation}
\label{eq:linear_comb}
 \hat{\boldsymbol{v}}_t(\alpha) = \alpha \hat{\boldsymbol{v}}^1_t + (1-\alpha) \hat{\boldsymbol{v}}^2_t, \qquad \alpha \in [0,1].
\end{equation}
\textbf{Asymptotic Bias.} 
It is a well-known property that SNIS estimators are biased in finite samples but asymptotically unbiased. Specifically, for each estimator $k \in \{1,2\}$, its expectation satisfies \cite{mcbook}:
\begin{equation}
 \mathbb{E}[\hat{\boldsymbol{v}}^k_t] = \boldsymbol{v}_t + \mathcal{O}(K_k^{-1}).
\end{equation}
Consequently, as a linear combination with weights summing to one, the combined estimator $\hat{\boldsymbol{v}}_t(\alpha)$ remains asymptotically unbiased, with the bias vanishing at a rate of $\mathcal{O}(\min(K_1, K_2)^{-1})$.
\textbf{Variance.} 
Assuming the two SNIS estimators are independent, the variance of the combined estimator is:
\begin{equation}
\label{eq:linear_var}
 \mathrm{Var}[\hat{\boldsymbol{v}}_t(\alpha)] = \alpha^2 \mathrm{Var}[\hat{\boldsymbol{v}}^1_t] + (1-\alpha)^2 \mathrm{Var}[\hat{\boldsymbol{v}}^2_t].
\end{equation}
Minimizing Eq.~\eqref{eq:linear_var} with respect to $\alpha$ yields the optimal weight:
\begin{equation}
\label{eq:optimal_alpha}
 \alpha^{\star} = \frac{\mathrm{Var}[\hat{\boldsymbol{v}}^2_t]}{\mathrm{Var}[\hat{\boldsymbol{v}}^1_t] + \mathrm{Var}[\hat{\boldsymbol{v}}^2_t]}.
\end{equation}
Thus, the minimum-variance estimator should assign larger weights to the component with smaller variance. For SNIS, the variance is approximately inversely proportional to the ESS:
\begin{equation}
 \mathrm{Var}[\hat{\boldsymbol{v}}^k_t] \propto \frac{1}{\mathrm{ESS}_k}.
\end{equation}
Substituting this approximation into Eq.~\eqref{eq:optimal_alpha}, we derive the adaptive ESS-weighted estimator employed in MFPO:
\begin{equation}
\label{eq:ess_weighted}
 \hat{\boldsymbol{v}}_t = \frac{\mathrm{ESS}_1}{\mathrm{ESS}_1 + \mathrm{ESS}_2} \hat{\boldsymbol{v}}^1_t + \frac{\mathrm{ESS}_2}{\mathrm{ESS}_1 + \mathrm{ESS}_2} \hat{\boldsymbol{v}}^2_t.
\end{equation}
This ESS-weighted estimator is asymptotically unbiased and achieves near-optimal variance among linear combinations of the two SNIS estimators.
As a result, the estimator automatically favors the proposal
that better matches the target distribution,
providing a stable and efficient instantaneous velocity estimation for MFPO.
\section{Algorithm Pseudo Code}
\begin{algorithm}[h]
\caption{Training of the Average Divergence Network}
\label{alg::avgdiv_train}
\begin{algorithmic}[1]
\State \textbf{Input:} policy network $\boldsymbol{u}_{\theta}$; average divergence network $\delta_{\omega}$; a batch of $B$ state-action pairs $\{(\boldsymbol{s}, \boldsymbol{a}_0)\}$ from the current policy
\State Sample $(r,t) \sim p(r,t)$ and $\boldsymbol{a}_1 \sim \mathcal{N}(\boldsymbol{0}, \boldsymbol{I})$
\State $\boldsymbol{a}_t \leftarrow (1-t)\boldsymbol{a}_0 + t \boldsymbol{a}_1$
\For{each $\boldsymbol{a}_t$ in the batch}
 \State Sample $\{\boldsymbol{\epsilon}_i\}_{i=1}^{N} \sim \mathcal{N}(\boldsymbol{0}, \boldsymbol{I})$
 \State Estimate divergence:
 \(
 \widehat{\mathrm{div}}(\boldsymbol{s}, \boldsymbol{a}_t, t)
 =
 \frac{1}{N}
 \sum_{i=1}^{N}
 \boldsymbol{\epsilon}_i^{\top}
 \frac{\partial \boldsymbol{u}_{\theta}(\boldsymbol{s}, \boldsymbol{a}_t, t, t)}
 {\partial \boldsymbol{a}_t}
 \boldsymbol{\epsilon}_i
 \)
 \State Construct target:
 \(
 \delta_{\mathrm{tgt}}(\boldsymbol{s}, \boldsymbol{a}_t, r, t)
 =
 \widehat{\mathrm{div}}
 -
 (t-r)
 \left(
 \boldsymbol{u}_{\theta}(\boldsymbol{s}, \boldsymbol{a}_t, t, t)\,\partial_{\boldsymbol{a}}\delta
 +
 \partial_t \delta
 \right)
 \)
\EndFor
\State Update parameters:
\(
\omega \leftarrow \arg\min_{\omega}
\frac{1}{B}
\sum
\left\|
\delta_{\omega}(\boldsymbol{s}, \boldsymbol{a}_t, r, t)
-
\operatorname{sg}\!\left(\delta_{\mathrm{tgt}}(\boldsymbol{s}, \boldsymbol{a}_t, r, t)\right)
\right\|_2^2
\)
\end{algorithmic}
\end{algorithm}
\begin{algorithm}[th]
\caption{MeanFlow Action Sampling and Likelihood Estimation}
\label{alg::sample}
\begin{algorithmic}[1]
\State \textbf{Input:} state $\boldsymbol{s}$; policy network $\boldsymbol{u}_{\theta}$; average divergence network $\delta_{\omega}$; number of sampling steps $T$; prior distribution $p_1$
\State Sample $\boldsymbol{a}_{t_T} \sim p_1(\boldsymbol{a}_1)$
\State Initialize $\log p(\boldsymbol{a}_{t_T}) \leftarrow \log p_1(\boldsymbol{a}_1)$
\For{$i = T, \ldots, 1$}
 \State $\boldsymbol{a}_{t_{i-1}} \leftarrow \boldsymbol{a}_{t_i}
 - \frac{1}{T}\, \boldsymbol{u}_{\theta}(\boldsymbol{s}, \boldsymbol{a}_{t_i}, t_{i-1}, t_i)$
 \State $\log p(\boldsymbol{a}_{t_{i-1}}) \leftarrow \log p(\boldsymbol{a}_{t_i})
 + \frac{1}{T}\, \delta_{\omega}(\boldsymbol{s}, \boldsymbol{a}_{t_i}, t_{i-1}, t_i)$
\EndFor
\State \textbf{Output:} action $\boldsymbol{a}_0$ and log-likelihood $\log p(\boldsymbol{a}_0)$
\end{algorithmic}
\end{algorithm}
\begin{algorithm}[h]
\caption{Mean Flow Policy Optimization (MFPO)}
\label{alg::mfpo}
\begin{algorithmic}[1]
\State \textbf{Input:} Q-network $Q_{\phi}$; target Q-network $Q_{\bar{\phi}}$; policy network $\boldsymbol{u}_{\theta}$; average divergence network $\delta_{\omega}$; temperature $\alpha$
\For{each iteration}
 \For{each interaction step}
 \State Sample $\boldsymbol{a} \sim \pi_{\theta}(\cdot | \boldsymbol{s})$ using Algorithm~\ref{alg::sample}
 \State Execute action and observe $(\boldsymbol{s}', r) = \mathrm{env}(\boldsymbol{a})$
 \State Store transition $(\boldsymbol{s}, \boldsymbol{a}, r, \boldsymbol{s}')$ in replay buffer $\mathcal{B}$
 \EndFor
 \For{each update step}
 \State Sample $B$ transitions $\{(\boldsymbol{s}, \boldsymbol{a}, r, \boldsymbol{s}')\}$ from $\mathcal{B}$
 \State \textcolor{gray}{\textit{// Policy evaluation:}}
 \State Sample $\boldsymbol{a}' \sim \pi_{\theta}(\cdot | \boldsymbol{s}')$ and compute $\log \pi_{\theta}(\boldsymbol{a}' | \boldsymbol{s}')$ using Algorithm~\ref{alg::sample}
 \State Compute target:
 \(
 Q_{\mathrm{target}} \leftarrow r
 + \gamma \left(
 Q_{\bar{\phi}}(\boldsymbol{s}', \boldsymbol{a}')
 - \alpha \log \pi_{\theta}(\boldsymbol{a}' | \boldsymbol{s}')
 \right)
 \)
 \State Update Q-network:
 \(
 \phi \leftarrow \arg\min_{\phi}
 \frac{1}{B}
 \sum
 \tfrac{1}{2}
 \big(
 Q_{\phi}(\boldsymbol{s}, \boldsymbol{a})
 -
 Q_{\mathrm{target}}
 \big)^2
 \)
 \State \textcolor{gray}{\textit{// Policy improvement:}}
 \State Sample $(r,t) \sim p(r,t)$
 \For{$k = 1,2$}
 \State Sample $\boldsymbol{a}_0 \sim q^{k}$
 \State Estimate instantaneous velocity via SNIS:
 \(
 \hat{\boldsymbol{v}}_t^{k}
 =
 \sum
 \frac{w(\boldsymbol{a}_0)}{\sum w(\boldsymbol{a}_0)}
 \cdot
 \frac{\boldsymbol{a}_t - \boldsymbol{a}_0}{t}
 \)
 \State Compute effective sample size:
 \(
 \mathrm{ESS}_k
 =
 \frac{\left(\sum w(\boldsymbol{a}_0)\right)^2}
 {\sum w^2(\boldsymbol{a}_0)}
 \)
 \EndFor
 \State Combine estimates:
 \(
 \hat{\boldsymbol{v}}_t
 =
 \frac{\mathrm{ESS}_1}{\mathrm{ESS}_1 + \mathrm{ESS}_2}\hat{\boldsymbol{v}}_t^{1}
 +
 \frac{\mathrm{ESS}_2}{\mathrm{ESS}_1 + \mathrm{ESS}_2}\hat{\boldsymbol{v}}_t^{2}
 \)
 \State Construct target:
 \(
 \boldsymbol{u}_{\mathrm{tgt}}
 =
 \hat{\boldsymbol{v}}_t
 -
 (t-r)
 \left(
 \hat{\boldsymbol{v}}_t\,\partial_{\boldsymbol{a}} \boldsymbol{u}_{\theta}
 +
 \partial_t \boldsymbol{u}_{\theta}
 \right)
 \)
 \State Update policy network:
 \(
 \theta \leftarrow \arg\min_{\theta}
 \frac{1}{B}
 \sum
 \left\|
 \boldsymbol{u}_{\theta}(\boldsymbol{s}, \boldsymbol{a}_t, r, t)
 -
 \operatorname{sg}(\boldsymbol{u}_{\mathrm{tgt}})
 \right\|_2^2
 \)
 \State Update the average divergence network $\delta_{\omega}$ using Algorithm~\ref{alg::avgdiv_train}
 \State Update target network: $\bar{\phi} \leftarrow \tau \phi + (1-\tau)\bar{\phi}$
 \EndFor
\EndFor
\end{algorithmic}
\end{algorithm}
\section{Experimental Details}
In this paper, all experiments are conducted on a server equipped with an NVIDIA GeForce RTX 3090 GPU and an Intel Xeon Platinum 8280 CPU. The implementations of baseline methods follow their official repositories: DIME\footnote{\url{https://github.com/ALRhub/DIME}}
, FlowRL\footnote{\url{https://github.com/bytedance/FlowRL}}
, MaxEntDP\footnote{\url{https://github.com/diffusionyes/MaxEntDP}}
, DACER\footnote{\url{https://github.com/happy-yan/DACER-Diffusion-with-Online-RL}}
