\section{Methodology}
\subsection{Preliminaries} 
\subsubsection{Spoken Dialogue Model}
\label{sec:unified_modeling}
We study spoken dialogue models that generate both \emph{text} and \emph{speech} given an input context $x$.
Different architectures realize the generation process differently:
(i) \textbf{Interleaving} generates a single interleaved token stream,
(ii) \textbf{Parallel} generates text and speech streams with coupled states,
and (iii) \textbf{Thinker--Talker} factorizes generation into a ``thinking'' stage and a ``speaking'' stage.
To remain architecture-agnostic, we represent the outputs as two token sequences:
a text sequence $\mathbf{y}^T=(y^T_1,\dots,y^T_L)$ and a speech sequence $\mathbf{y}^S=(y^S_1,\dots,y^S_M)$.
For each emitted token, $c^T_i$ and $c^S_j$ denote its conditioning context under the chosen architecture
(e.g., previous tokens in an interleaved stream, cross-stream hidden states, or a preceding-stage output).
\paragraph{Token-type partition of log-likelihood.}
The model defines a joint conditional distribution $P_\theta(\mathbf{y}^T,\mathbf{y}^S\mid x)$.
Regardless of the internal dependency pattern, the log-likelihood can be partitioned by token types:
\begin{equation}
\label{eq:unified_logprob}
\begin{split}
\log P_\theta(\mathbf{y}^T, &\mathbf{y}^S \mid x) 
&= \sum_{i=1}^{L} \log P_\theta(y^T_i \mid c^T_i) 
&\quad + \sum_{j=1}^{M} \log P_\theta(y^S_j \mid c^S_j).
\end{split}
\end{equation}
\subsection{Post-Training Algorithms}
\label{sec:post_training}
\subsubsection{Supervised fine-tuning (SFT)}
\label{sec:sft}
Given demonstrations $\mathcal{D}_{\mathrm{sup}}=\{(x,y^{\star})\}$,
SFT minimizes the teacher-forcing cross-entropy:
\begin{equation}
\label{eq:sft}
\begin{split}
\mathcal{L}_{\mathrm{SFT}}&(\theta)
= 
&-\mathbb{E}_{(x,y^{\star})\sim \mathcal{D}_{\mathrm{sup}}}
\left[
\sum_{t=1}^{|y^{\star}|}
\log \pi_{\theta}\!\left(y^{\star}_t \mid x, y^{\star}_{<t}\right)
\right].
\end{split}
\end{equation}
\noindent\textbf{Property (dense token-level constraint).}
SFT provides a \emph{dense} learning signal at every token position. It is typically the most stable objective.
\subsubsection{Group Relative Policy Optimization}
\label{sec:grpo_full}
For each $x$, GRPO samples a group of $G$ trajectories $\{y^{(i)}\}_{i=1}^{G}$
from a behavior policy $\pi_{\theta_{\mathrm{old}}}(\cdot\mid x)$
and obtains rewards $\{R^{(i)}\}_{i=1}^{G}$ where $R^{(i)}\triangleq R(x,y^{(i)})$.
It uses a group-relative advantage $\hat{A}^{(i)}$ and a PPO-style clipped surrogate with KL regularization:
\begin{equation}
\label{eq:grpo_sketch}
\begin{split}
\mathcal{L}_{\mathrm{GRPO}}&(\theta) = -\,\mathbb{E}\Bigg[ \frac{1}{G}\sum_{i=1}^{G} \sum_{t=1}^{|y^{(i)}|} \min\Bigg( 
&\quad \rho^{(i)}_{t}\,\hat{A}^{(i)}, 
&\quad \mathrm{clip}\big(\rho^{(i)}_{t}, 1-\epsilon, 1+\epsilon\big)\,\hat{A}^{(i)}
\Bigg) \Bigg] 
&+\; \beta\, \mathbb{E}\Big[ \mathrm{KL}\!\big(\pi_{\theta}(\cdot\mid x)\,\|\,\pi_{\mathrm{ref}}(\cdot\mid x)\big) \Big],
\end{split}
\end{equation}
where $\epsilon$ is $\epsilon_{\mathrm{clip}}$ for brevity, and the token-level importance ratio is
$
\rho^{(i)}_{t}
=
\frac{\pi_{\theta}(y^{(i)}_{t}\mid x, y^{(i)}_{<t})}{\pi_{\theta_{\mathrm{old}}}(y^{(i)}_{t}\mid x, y^{(i)}_{<t})}
$.
\noindent\textbf{Property (online; sparse credit shared across tokens).}
GRPO is an \emph{online} method that requires rollouts to obtain rewards.
Although loss are computed at the token level, the advantage $\hat{A}^{(i)}$ is sequence-level (shared across token positions),
which can make credit assignment challenging for long and dense token streams. The KL term acts as a \emph{dense} trust-region constraint that stabilizes optimization and prevents excessive policy drift.
\subsubsection{Offline DPO-family}
\label{sec:dpo_full}
Given pairwise preference data $\mathcal{D}_{\mathrm{pref}}=\{(x,y^{+},y^{-})\}$,
DPO optimizes a logistic loss on the reference-corrected log-ratio gap.
We define
\begin{equation}
\label{eq:dpo_delta}
\begin{split}
\Delta(x,&y^{+},y^{-};\theta) 
&= \Big(\log \pi_{\theta}(y^{+}\mid x) - \log \pi_{\theta}(y^{-}\mid x)\Big) 
&\quad - \Big(\log \pi_{\mathrm{ref}}(y^{+}\mid x) - \log \pi_{\mathrm{ref}}(y^{-}\mid x)\Big),
\end{split}
\end{equation}
and minimize
\begin{equation}
\label{eq:dpo_loss}
\begin{split}
\mathcal{L}_{\mathrm{DPO}}&(\theta) = 
&-\mathbb{E}_{\mathcal{D}_{\mathrm{pref}}}
\Big[
\log \sigma\!\big(\gamma\cdot \Delta(x,y^{+},y^{-};\theta)\big)
\Big],
\end{split}
\end{equation}
where $\sigma(\cdot)$ is the logistic sigmoid and $\gamma>0$ is a temperature.
\noindent\textbf{Property (offline; sparse preference supervision).}
DPO is \emph{offline} and does not require rollouts during optimization, making it scalable in practice.
Supervision signal comes only from pairwise preferences and performance depends on preference quality/coverage and potential judge bias.
\paragraph{Token-subset restricted likelihood.}
In mixed-modality settings, it is sometimes useful to restrict preference-driven updates to a subset of token positions.
Given an index set $\mathcal{M}(y)\subseteq \{1,\ldots,|y|\}$, define the masked score:
\begin{equation}
\label{eq:masked_score}
s_{\mathcal{M}}(x,y;\theta)
\triangleq
\sum_{t\in \mathcal{M}(y)}
\log \pi_{\theta}\!\left(y_t \mid x, y_{<t}\right).
\end{equation}
Replacing $\log \pi_\theta(y\mid x)$ with $s_{\mathcal{M}}(x,y;\theta)$ yields token-subset restricted variants of
SFT/PO objectives, enabling explicit control over which token types receive preference gradients.
